import pandas as pd# ==========================================================# Helper Functions# ==========================================================def safe_feature_sum(filtered_df):    """    Sum Feature_Count, treating missing values as 1.    If Feature_Count does not exist, count rows instead.    """    if filtered_df.empty:        return 0    if "Feature_Count" in filtered_df.columns:        return filtered_df["Feature_Count"].fillna(1).sum()    return len(filtered_df)# ==========================================================# Desert Tortoise Metrics# ==========================================================def live_adt_count(df):    filtered = df[df["Type_ID"].isin([5, 6])]    return safe_feature_sum(filtered)def class_1_count(df):    return (        (df["Type_ID"] == 6)        | (            (df["Type_ID"] == 7)            & (df["Status_1"] == "Class 1")        )    ).sum()def class_2_count(df):    return (        (df["Type_ID"] == 7)        & (df["Status_1"] == "Class 2")    ).sum()def class_3_count(df):    return (        (df["Type_ID"] == 7)        & (df["Status_1"] == "Class 3")    ).sum()def class_4_count(df):    return (        (df["Type_ID"] == 7)        & (df["Status_1"] == "Class 4")    ).sum()def class_5_count(df):    return (        (df["Type_ID"] == 7)        & (df["Status_1"] == "Class 5")    ).sum()def undefined_class_count(df):    return (        (df["Type_ID"] == 7)        & (df["Status_1"] == "Class unknown or not listed")    ).sum()def no_longer_or_not_found_count(df):    return (        (df["Type_ID"] == 7)        & (            df["Status_1"].isin(                [                    "Can't Find Burrow",                    "No longer a tortoise burrow",                    "Not Surveyed (skipped)",                ]            )        )    ).sum()# ==========================================================# Scat Metrics# ==========================================================def ty_scat_count(df):    return (        df["Type_ID"].isin([6, 7, 8])        & df["Status_3"].isin(["TY1", "TY2", "TY3"])    ).sum()def nty_scat_count(df):    return (        df["Type_ID"].isin([6, 7, 8])        & df["Status_3"].str.contains("NTY", case=False, na=False)    ).sum()# ==========================================================# Carcass Metrics# ==========================================================def adt_carcass_0_1_count(df):    return (        (df["Type_ID"] == 9)        & (df["Status_1"] == "0-1 YR")    ).sum()def adt_carcass_1_2_count(df):    return (        (df["Type_ID"] == 9)        & (df["Status_1"] == "1-2 YRS")    ).sum()def adt_carcass_older_than_2_count(df):    return (        (df["Type_ID"] == 9)        & (            ~df["Status_1"].isin(                [                    "0-1 YR",                    "1-2 YRS",                ]            )        )    ).sum()# ==========================================================# Other Sign Metrics# ==========================================================def adt_tracks_count(df):    return (        df["Type_ID"].isin([6, 7, 8, 10])        & (df["Status_4"] == "Tracks")    ).sum()def adt_eggshells_count(df):    return (        df["Type_ID"].isin([6, 7, 8, 10])        & (df["Status_4"] == "Other sign")        & (            df["Comments"].str.contains(                r"egg|eggshell",                case=False,                na=False,            )        )    ).sum()def total_other_adt_sign_count(df):    return (        df["Type_ID"].isin([6, 7, 8, 9])        & df["Status_4"].notna()        & (df["Status_4"] != "No other sign observed")    ).sum()# ==========================================================# Dictionary of ADT Metrics# ==========================================================summary_functions = {    # Desert Tortoise    "live_adt_count": live_adt_count,    "class_1_count": class_1_count,    "class_2_count": class_2_count,    "class_3_count": class_3_count,    "class_4_count": class_4_count,    "class_5_count": class_5_count,    "undefined_class_count": undefined_class_count,    "no_longer_or_not_found_count": no_longer_or_not_found_count,    # Scat    "ty_scat_count": ty_scat_count,    "nty_scat_count": nty_scat_count,    # Carcass    "adt_carcass_0_1_count": adt_carcass_0_1_count,    "adt_carcass_1_2_count": adt_carcass_1_2_count,    "adt_carcass_older_than_2_count": adt_carcass_older_than_2_count,    # Other Sign    "adt_tracks_count": adt_tracks_count,    "adt_eggshells_count": adt_eggshells_count,    "total_other_adt_sign_count": total_other_adt_sign_count,}DISPLAY_NAME = "ADT Summary"FILE_PREFIX = "ADT"